import{_ as a,c as s,a1 as i,o}from"./chunks/framework.DiyHpDmR.js";const u=JSON.parse('{"title":"K8s 部署","description":"","frontmatter":{},"headers":[],"relativePath":"deploy/k8s.md","filePath":"deploy/k8s.md","lastUpdated":1782643526000}'),t={name:"deploy/k8s.md"};function l(n,e,c,r,d,p){return o(),s("div",null,e[0]||(e[0]=[i(`<h1 id="k8s-部署" tabindex="-1">K8s 部署 <a class="header-anchor" href="#k8s-部署" aria-label="Permalink to &quot;K8s 部署&quot;">​</a></h1><p>K8s 是 Firefly 的云原生目标路线。当前官方 Go 模板优先覆盖裸机 / IDC 主线；K8s 文档先给出迁移边界和服务侧约束，具体 Helm / Operator 形态会随 <code>go-k8s</code> 与 Service Mesh 集成继续补齐。</p><h2 id="目标模型" tabindex="-1">目标模型 <a class="header-anchor" href="#目标模型" aria-label="Permalink to &quot;目标模型&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>业务服务</span></span>
<span class="line"><span>  -&gt; Kubernetes Service / EndpointSlice</span></span>
<span class="line"><span>  -&gt; CoreDNS</span></span>
<span class="line"><span>  -&gt; Istio / Envoy</span></span>
<span class="line"><span>  -&gt; authz ext_authz</span></span></code></pre></div><p>业务代码仍然保持同一条语义：</p><ul><li>服务只表达目标 Service DNS。</li><li>不直接依赖注册中心 SDK。</li><li>不在业务层做实例发现和负载均衡。</li><li>入站上下文仍由 <code>go-micro/service.Context</code> 承载。</li></ul><h2 id="配置数据面" tabindex="-1">配置数据面 <a class="header-anchor" href="#配置数据面" aria-label="Permalink to &quot;配置数据面&quot;">​</a></h2><p>配置中心主线按部署环境选择数据源实现：</p><ul><li>裸机 / IDC：<code>go-consul/config</code>。</li><li>K8s / Istio：<code>go-k8s/config</code>。</li></ul><p>这不是“单个二进制同时切换两套后端”，而是按部署产物选择唯一实现。业务服务应面向 <code>go-micro/config</code> 契约组织配置读取。</p><h2 id="manifest-与路由" tabindex="-1">Manifest 与路由 <a class="header-anchor" href="#manifest-与路由" aria-label="Permalink to &quot;Manifest 与路由&quot;">​</a></h2><p>即使进入 K8s，协议驱动仍然有效：</p><ul><li>业务 proto 通过 Buf 生成服务端代码。</li><li><code>protoc-gen-gateway-manifest</code> 生成 <code>gateway.manifest.json</code>。</li><li>HTTP/JSON 转 gRPC 需要 descriptor set。</li><li>route facts 仍应包含 <code>app_id</code>、<code>method</code> 和 <code>path</code>。</li></ul><p>后续如果入口完全由 Istio IngressGateway 承接，manifest 可以继续作为接口事实和治理输入，而不是业务 HTTP handler 的替代品。</p><h2 id="当前建议" tabindex="-1">当前建议 <a class="header-anchor" href="#当前建议" aria-label="Permalink to &quot;当前建议&quot;">​</a></h2><ul><li>先用 <code>go-layout</code> 固化 Service / Biz / Data 分层和 Proto 契约。</li><li>裸机联调完成后，再把运行时能力迁移到 K8s Service、EndpointSlice、CoreDNS 和 Istio。</li><li>不要在业务代码中加入只为某个注册中心服务的 discovery / LB 逻辑。</li><li>本地验签、service authority、OTel 传播规则应与裸机主线保持一致。</li></ul>`,16)]))}const f=a(t,[["render",l]]);export{u as __pageData,f as default};
